+
+    #[test]
+    fn macro_def_serde_roundtrip() {
+        let def = MacroDef::new(
+            "test-macro",
+            vec![
+                MacroStep::new("screen:Messages", "Messages"),
+                MacroStep::new("screen:Threads", "Threads").with_delay(500),
